<?php

namespace App\Helpers;

use App\Models\Menu;
use Illuminate\Support\Facades\Auth;

class MenuHelper
{
    public static function getMenuGroups(): array
    {
        $user = Auth::user();

        $menus = Menu::active()
            ->ordered()
            ->parentMenus()
            ->with(['children' => function ($query) {
                $query->active()->ordered()->with('roles');
            }, 'roles'])
            ->get();

        $grouped = [];

        foreach ($menus as $menu) {
            // Cek akses role jika punya pembatasan
            if ($menu->roles->count() > 0 && $user && !$user->hasRole('superadmin')) {
                $hasAccess = false;
                foreach ($menu->roles as $role) {
                    if ($user->hasRole($role->name)) {
                        $hasAccess = true;
                        break;
                    }
                }
                if (!$hasAccess) continue;
            }

            $groupName = $menu->group_name ?? 'Menu';

            if (!isset($grouped[$groupName])) {
                $grouped[$groupName] = [
                    'title' => $groupName,
                    'items' => [],
                ];
            }

            $item = [
                'icon' => $menu->icon ?? 'dashboard',
                'name' => $menu->name,
                'path' => $menu->route ? route($menu->route, [], false) : ($menu->url ?? '#'),
            ];

            // Cek children
            $children = [];
            foreach ($menu->children as $child) {
                if ($child->roles->count() > 0 && $user && !$user->hasRole('superadmin')) {
                    $hasChildAccess = false;
                    foreach ($child->roles as $role) {
                        if ($user->hasRole($role->name)) {
                            $hasChildAccess = true;
                            break;
                        }
                    }
                    if (!$hasChildAccess) continue;
                }

                $children[] = [
                    'name' => $child->name,
                    'path' => $child->route ? route($child->route, [], false) : ($child->url ?? '#'),
                ];
            }

            if (count($children) > 0) {
                unset($item['path']);
                $item['subItems'] = $children;
            }

            $grouped[$groupName]['items'][] = $item;
        }

        return array_values($grouped);
    }

